      'x-vercel-ip-country': 'DE',
      'x-vercel-ip-city': 'Berlin',
      'x-vercel-ip-latitude': '52.52',
      'x-vercel-ip-longitude': '13.405',
      'x-vercel-ip-timezone': 'Europe/Berlin',
    }

    const geo = extractGeoData(headers)
    expect(geo.country).toBe('DE')
    expect(geo.city).toBe('Berlin')
    expect(geo.countryRegion).toBeUndefined()
  })

  it('falls back to Cloudflare cf-ipcountry when Vercel header is absent', () => {
    const headers = new Headers({
      'cf-ipcountry': 'GB',
    })

    const geo = extractGeoData(headers)
    expect(geo.country).toBe('GB')
    expect(geo.countryRegion).toBeUndefined()
    expect(geo.city).toBeUndefined()
  })

  it('prefers Vercel header over Cloudflare when both are present', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'US',
      'cf-ipcountry': 'GB',
    })

    const geo = extractGeoData(headers)
    expect(geo.country).toBe('US')
  })

  it('returns all undefined fields when no geo headers are present', () => {
    const headers = new Headers({
      'content-type': 'text/html',
    })

    const geo = extractGeoData(headers)
    expect(geo).toStrictEqual({
      country: undefined,
      countryRegion: undefined,
      city: undefined,
      latitude: undefined,
      longitude: undefined,
      timezone: undefined,
    })
  })

  it('handles plain object with array values', () => {
    const headers: Record<string, string | string[]> = {
      'x-vercel-ip-country': ['JP'],
    }

    const geo = extractGeoData(headers)
    expect(geo.country).toBe('JP')
  })

  it('returns undefined for empty string header values', () => {
    const headers = new Headers({
      'x-vercel-ip-country': '',
    })

    const geo = extractGeoData(headers)
    expect(geo.country).toBeUndefined()
  })
})

// ---------------------------------------------------------------------------
// getCountryName
// ---------------------------------------------------------------------------

describe('getCountryName', () => {
  it('returns the English name for a known country code', () => {
    expect(getCountryName('US')).toBe('United States')
    expect(getCountryName('DE')).toBe('Germany')
    expect(getCountryName('JP')).toBe('Japan')
    expect(getCountryName('BR')).toBe('Brazil')
  })

  it('is case-insensitive', () => {
    expect(getCountryName('us')).toBe('United States')
    expect(getCountryName('de')).toBe('Germany')
  })

  it('returns undefined for unknown codes', () => {
    expect(getCountryName('XX')).toBeUndefined()
    expect(getCountryName('ZZ')).toBeUndefined()
  })

  it('returns undefined for empty or invalid input', () => {
    expect(getCountryName('')).toBeUndefined()
    expect(getCountryName('A')).toBeUndefined()
    expect(getCountryName('USA')).toBeUndefined()
  })

  it('supports a locale parameter', () => {
    const name = getCountryName('DE', 'de')
    // In German, Germany is "Deutschland"
    expect(name).toBe('Deutschland')
  })
})

// ---------------------------------------------------------------------------
// isInRegion
// ---------------------------------------------------------------------------

describe('isInRegion', () => {
  describe('EU region', () => {
    it('returns true for EU member states', () => {
      expect(isInRegion('DE', 'EU')).toBe(true)
      expect(isInRegion('FR', 'EU')).toBe(true)
      expect(isInRegion('IT', 'EU')).toBe(true)
      expect(isInRegion('ES', 'EU')).toBe(true)
      expect(isInRegion('PL', 'EU')).toBe(true)
    })

    it('returns false for non-EU countries', () => {
      expect(isInRegion('US', 'EU')).toBe(false)
      expect(isInRegion('GB', 'EU')).toBe(false)
      expect(isInRegion('NO', 'EU')).toBe(false)
      expect(isInRegion('CH', 'EU')).toBe(false)
    })
  })

  describe('EEA region', () => {
    it('includes EU countries', () => {
      expect(isInRegion('DE', 'EEA')).toBe(true)
      expect(isInRegion('FR', 'EEA')).toBe(true)
    })

    it('includes Iceland, Liechtenstein, and Norway', () => {
      expect(isInRegion('IS', 'EEA')).toBe(true)
      expect(isInRegion('LI', 'EEA')).toBe(true)
      expect(isInRegion('NO', 'EEA')).toBe(true)
    })

    it('excludes non-EEA countries', () => {
      expect(isInRegion('US', 'EEA')).toBe(false)
      expect(isInRegion('CH', 'EEA')).toBe(false)
    })
  })

  describe('NA region', () => {
    it('returns true for North American countries', () => {
      expect(isInRegion('US', 'NA')).toBe(true)
      expect(isInRegion('CA', 'NA')).toBe(true)
      expect(isInRegion('MX', 'NA')).toBe(true)
    })

    it('returns false for non-NA countries', () => {
      expect(isInRegion('BR', 'NA')).toBe(false)
      expect(isInRegion('DE', 'NA')).toBe(false)
    })
  })

  describe('SA region', () => {
    it('returns true for South American countries', () => {
      expect(isInRegion('BR', 'SA')).toBe(true)
      expect(isInRegion('AR', 'SA')).toBe(true)
      expect(isInRegion('CL', 'SA')).toBe(true)
    })

    it('returns false for non-SA countries', () => {
      expect(isInRegion('US', 'SA')).toBe(false)
    })
  })

  describe('AS region', () => {
    it('returns true for Asian countries', () => {
      expect(isInRegion('JP', 'AS')).toBe(true)
      expect(isInRegion('CN', 'AS')).toBe(true)
      expect(isInRegion('IN', 'AS')).toBe(true)
    })
  })

  describe('AF region', () => {
    it('returns true for African countries', () => {
      expect(isInRegion('NG', 'AF')).toBe(true)
      expect(isInRegion('ZA', 'AF')).toBe(true)
      expect(isInRegion('EG', 'AF')).toBe(true)
    })
  })

  describe('OC region', () => {
    it('returns true for Oceanian countries', () => {
      expect(isInRegion('AU', 'OC')).toBe(true)
      expect(isInRegion('NZ', 'OC')).toBe(true)
      expect(isInRegion('FJ', 'OC')).toBe(true)
    })
  })

  describe('EU_GEO region', () => {
    it('includes EU members and other European countries', () => {
      expect(isInRegion('DE', 'EU_GEO')).toBe(true)
      expect(isInRegion('GB', 'EU_GEO')).toBe(true)
      expect(isInRegion('CH', 'EU_GEO')).toBe(true)
      expect(isInRegion('NO', 'EU_GEO')).toBe(true)
    })
  })

  it('is case-insensitive for country codes', () => {
    expect(isInRegion('de', 'EU')).toBe(true)
    expect(isInRegion('us', 'NA')).toBe(true)
  })

  it('is case-insensitive for region names', () => {
    expect(isInRegion('DE', 'eu')).toBe(true)
    expect(isInRegion('US', 'na')).toBe(true)
  })

  it('returns false for unknown regions', () => {
    expect(isInRegion('US', 'UNKNOWN')).toBe(false)
  })

  it('returns false for empty inputs', () => {
    expect(isInRegion('', 'EU')).toBe(false)
    expect(isInRegion('DE', '')).toBe(false)
  })
})

// ---------------------------------------------------------------------------
// haversineDistance
// ---------------------------------------------------------------------------

describe('haversineDistance', () => {
  it('calculates distance between San Francisco and New York', () => {
    const sf = { latitude: 37.7749, longitude: -122.4194 }
    const ny = { latitude: 40.7128, longitude: -74.006 }

    const distance = haversineDistance(sf, ny)
    // Known distance is approximately 4129 km
    expect(distance).toBeGreaterThan(4100)
    expect(distance).toBeLessThan(4200)
  })

  it('calculates distance between London and Tokyo', () => {
    const london = { latitude: 51.5074, longitude: -0.1278 }
    const tokyo = { latitude: 35.6762, longitude: 139.6503 }

    const distance = haversineDistance(london, tokyo)
    // Known distance is approximately 9560 km
    expect(distance).toBeGreaterThan(9500)
    expect(distance).toBeLessThan(9600)
  })

  it('returns 0 for the same point', () => {
    const point = { latitude: 48.8566, longitude: 2.3522 }
    expect(haversineDistance(point, point)).toBe(0)
  })

  it('calculates distance between antipodal points', () => {
    const north = { latitude: 90, longitude: 0 }
    const south = { latitude: -90, longitude: 0 }

    const distance = haversineDistance(north, south)
    // Half the Earth's circumference ≈ 20015 km
    expect(distance).toBeGreaterThan(20000)
    expect(distance).toBeLessThan(20100)
  })

  it('is symmetric (order does not matter)', () => {
    const a = { latitude: 37.7749, longitude: -122.4194 }
    const b = { latitude: 48.8566, longitude: 2.3522 }

    expect(haversineDistance(a, b)).toBeCloseTo(haversineDistance(b, a), 10)
  })

  it('handles coordinates crossing the date line', () => {
    const nz = { latitude: -41.2865, longitude: 174.7762 }
    const fiji = { latitude: -17.7134, longitude: 178.065 }

    const distance = haversineDistance(nz, fiji)
    // Should be approximately 2650 km
    expect(distance).toBeGreaterThan(2600)
    expect(distance).toBeLessThan(2700)
  })

  it('handles coordinates at the equator', () => {
    const quito = { latitude: 0, longitude: -78.5 }
    const nairobi = { latitude: 0, longitude: 36.8 }

    const distance = haversineDistance(quito, nairobi)
    // Along the equator, approximately 12836 km
    expect(distance).toBeGreaterThan(12800)
    expect(distance).toBeLessThan(12900)
  })
})

